def search_in_matrix(grid: list[list[int]], val: int) -> bool:
    if not grid or not grid[0]:
        return False
    m, n = len(grid), len(grid[0])
    left, right = 0, m * n - 1
    while left <= right:
        middle = (left + right) // 2
        r = middle // n
        c = middle % n
        if grid[r][c] == val:
            return True
        elif grid[r][c] < val:
            left = middle + 1
        else:
            right = middle - 1
    return False

