def max_product_subarray_with_indices(nums: list[int]) -> tuple[int, int, int]:
    """
    Finds the maximum product subarray and its indices.
    """
    n = len(nums)
    best_prod = nums[0]
    best_start = 0
    best_end = 0

    for i in range(n):
        curr_prod = 1
        for j in range(i, n):
            curr_prod *= nums[j]
            is_better = False
            if curr_prod > best_prod:
                is_better = True
            elif curr_prod == best_prod:
                if i < best_start:
                    is_better = True
                elif i == best_start:
                    if (j - i) < (best_end - best_start):
                        is_better = True

            if is_better:
                best_prod = curr_prod
                best_start = i
                best_end = j

    return (best_prod, best_start, best_end)

