import re

def validate_ip_mask(ip_str: str) -> bool:
    match = re.match(r'^([^/]+)(?:/([^/]+))?$', ip_str)
    if not match:
        return False
    ip_part, mask_part = match.groups()
    octets = ip_part.split('.')
    if len(octets) != 4:
        return False
    for octet in octets:
        if not octet.isdigit():
            return False
        if len(octet) > 1 and octet[0] == '0':
            return False
        val = int(octet)
        if val < 0 or val > 255:
            return False
    if mask_part is not None:
        if not mask_part.isdigit():
            return False
        if len(mask_part) > 1 and mask_part[0] == '0':
            return False
        mask_val = int(mask_part)
        if mask_val < 0 or mask_val > 32:
            return False
    return True

def is_valid_ipv4_with_mask(address: str) -> bool:
    parts = address.split('/')
    if len(parts) > 2 or len(parts) == 0:
        return False
    ip_part = parts[0]
    octets = ip_part.split('.')
    if len(octets) != 4:
        return False
    for octet in octets:
        if not octet.isdigit():
            return False
        val = int(octet)
        if val < 0 or val > 255:
            return False
    if len(parts) == 2:
        mask_part = parts[1]
        if not mask_part.isdigit():
            return False
        mask_val = int(mask_part)
        if mask_val < 0 or mask_val > 32:
            return False
    return True

